const filmingPlanUrl = $input.first().json.body.filmingPlans || '';
const match = filmingPlanUrl.match(/\/document\/d\/([a-zA-Z0-9_-]+)/);
if (!match) {
  throw new Error('No valid Google Doc URL found in filmingPlans field. Got: ' + filmingPlanUrl);
}
const docId = match[1];
const exportUrl = `https://docs.google.com/document/d/${docId}/export?format=txt`;
return [{ json: { ...($input.first().json), docId, exportUrl } }];

