const response = $('Create Parent Issue').item.json;

if (!response?.data?.issueCreate?.issue?.id) {
  throw new Error('Linear rejected the mutation: ' + JSON.stringify(response));
}

const parentIssueId = response.data.issueCreate.issue.id;
const videos = $('Webhook').item.json.body.videos;

return videos.map(v => ({
  json: {
    parentId: parentIssueId,
    videoNumber: v.number
  }
}));

